// jwtAuthMiddleware.ts
import express, { Request, Response, NextFunction } from 'express';
import jwt, { JwtPayload } from 'jsonwebtoken';
import { jwtErrorResponse } from './jwtErrorResponse';
import { UserPayload, filterUserPayload } from './userPayload';

// 서버 부트 단계에서 환경 변수 검증
const JWT_SECRET = process.env.JWT_SECRET;
if (!JWT_SECRET) {
  console.error('JWT_SECRET 환경변수가 설정되어야 합니다.');
  process.exit(1);
}

const ALLOWED_ALGORITHMS = ['HS256'];

/**
 * JWT 인증 미들웨어
 *
 * 인증 성공 시, req.user에 필터된 payload 저장.
 * 인증 실패 시, 401 Unauthorized 반환.
 */
export function jwtAuthMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
) {
  const authHeader = req.headers['authorization'];

  if (!authHeader) {
    return res
      .status(401)
      .json(jwtErrorResponse('인증 토큰이 필요합니다.'));
  }

  // Authorization 헤더 형식: 'Bearer <token>'
  const [scheme, token] = authHeader.split(' ');

  if (scheme !== 'Bearer' || !token) {
    return res
      .status(401)
      .json(jwtErrorResponse('유효하지 않은 인증 형식입니다.'));
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ALLOWED_ALGORITHMS,
    });

    // 타입 안전 처리: object payload만 허용
    if (typeof decoded !== 'object' || decoded === null) {
      return res
        .status(401)
        .json(jwtErrorResponse('유효하지 않은 토큰입니다.'));
    }

    // payload 필터링 (민감 정보 및 jwt 내부 필드 제외)
    req.user = filterUserPayload(decoded);
    next();
  } catch (err) {
    // 민감 정보가 포함된 에러 메시지 노출 방지
    return res
      .status(401)
      .json(jwtErrorResponse('유효하지 않은 토큰입니다.'));
  }
}

// userPayload.ts
export interface UserPayload {
  id: string;
  email: string;
  [key: string]: unknown;
}

// JwtPayload에서 주요 필드만 추출 & 민감 정보 제거
export function filterUserPayload(decoded: any): UserPayload {
  return {
    id: decoded.id,
    email: decoded.email,
    // 필요 시 whitelist 필드 추가 가능
  };
}

// jwtErrorResponse.ts
export function jwtErrorResponse(message: string) {
  return {
    error: {
      code: 'JWT_AUTH_ERROR',
      message,
    },
  };
}

// global.d.ts (*별도 파일*)
declare global {
  namespace Express {
    interface Request {
      user?: UserPayload;
    }
  }
}

// 사용 예시 (app.ts)
import express from 'express';
import { jwtAuthMiddleware } from './jwtAuthMiddleware';

const app = express();

app.get('/protected', jwtAuthMiddleware, (req, res) => {
  res.json({
    message: '인증된 사용자입니다.',
    user: req.user,
  });
});

export default app;

## Bun + TypeScript 기반 실시간 채팅 서버 설계 (프로덕션 수준)

### 1. 아키텍처 개요
- **수평 확장 지원**: Bun 서버는 Kubernetes/Nomad 등 컨테이너 기반으로 수평 확장. WebSocket 세션 및 메시지 브로드캐스트는 Redis Pub/Sub을 통해 노드 간 공유.
- **로드밸런싱**: WebSocket-aware 로드밸런서(예: NGINX, HAProxy, AWS ALB 등) 사용.
- **데이터베이스**: PostgreSQL(또는 MySQL) + Prisma/Drizzle ORM으로 메시지/유저 영속화. 메시지 테이블 인덱싱.
- **캐시/브로드캐스트**: Redis를 Pub/Sub 및 세션 관리(peak-tracking) 및 메시지 캐싱에 사용.
- **보안**: .env 기반 시크릿 관리, JWT exp/iat/iss/aud 필드 검증, refresh token 플로우, bcrypt 비밀번호 해싱, HTTPS 적용, WebSocket 연결 시 토큰은 Cookie/Secure Header로 전달. TLS 전체 적용.
- **운영/관찰성**: Bun의 로깅, 메트릭/헬스체크 엔드포인트, rate limiting, ping/pong heartbeat, backpressure 처리, 테스트·벤치마크 시나리오 반영.

### 2. 폴더 구조 및 주요 모듈
```
src/
  config/
    env.ts            // 환경변수 및 시크릿 관리
  models/
    user.ts           // 유저 모델 (Prisma/Drizzle)
    message.ts        // 메시지 모델
  services/
    auth.ts           // JWT 발급/검증
    userService.ts    // 유저 로직
    messageService.ts // 메시지 영속화/조회
    wsBroadcast.ts    // Redis Pub/Sub 및 WebSocket 브로드캐스트
  routes/
    login.ts          // /login 엔드포인트
    messages.ts       // /messages 엔드포인트
  ws/
    wsServer.ts       // WebSocket 서버 (세션 관리, 인증, ping/pong etc)
  utils/
    logger.ts         // 로깅
    rateLimiter.ts    // IP별 rate limiting
  server.ts           // Bun 서버 엔트리 포인트
```

### 3. 메시지 테이블 스키마
```prisma
datasource db {
  provider = "postgresql"
  url = env("DATABASE_URL")
}

model User {
  id        String    @id @default(uuid())
  username  String    @unique
  password  String    // bcrypt hash
}

model Message {
  id        String    @id @default(uuid())
  content   String
  senderId  String
  timestamp DateTime  @default(now())
  sender    User      @relation(fields: [senderId], references: [id])
  index([timestamp]) // 인덱싱
}
```

### 4. Redis Pub/Sub 채팅 브로드캐스트 흐름
1. 각 Bun 노드에서 WebSocket 메시지 송수신
2. 메시지를 Redis Pub/Sub 채널에 publish
3. 모든 노드는 subscribe하여 메시지 받아 브로드캐스트

### 5. 인증 및 보안 흐름
- JWT 시크릿, DB 커넥션 등은 .env 파일로 관리
- Password hash: bcrypt 적용
- JWT Payload: userId, exp, iat, iss("chat-server"), aud("chat-client"), refresh토큰 발급/갱신
- HTTP Only Secure Cookie로 전달, WebSocket 연결시 header에 JWT
- WebSocket handshake에서 JWT 검증(만료, issuer, audience 체크), 비정상시 연결 거부함

### 6. 주요 엔드포인트
- `POST /login`: username/password 받아 bcrypt 검증 → JWT/refreshToken 발급, cookie로 전달
- `POST /refresh`: refreshToken 검증 → new JWT 발급
- `GET /messages`: JWT 인증, 최근 N개 메시지 조회 (cursor, timestamp 기준)
- `WebSocket /chat`: 커넥션 인증, 실시간 송수신, heartbeat(ping/pong), backpressure/queue 처리

### 7. 샘플 코드 조각 (Bun + TypeScript)

#### 환경 설정 (config/env.ts)
```typescript
import { loadEnv } from "bun";
// .env에는 SECRET, DB URL, REDIS URL 등 관리
type EnvConfig = {
  jwtSecret: string;
  dbUrl: string;
  redisUrl: string;
};
export const env: EnvConfig = {
  jwtSecret: Bun.env.JWT_SECRET!,
  dbUrl: Bun.env.DATABASE_URL!,
  redisUrl: Bun.env.REDIS_URL!,
