```

#### 인증 로직 (services/auth.ts)
```typescript
import jwt from "jsonwebtoken";
import bcrypt from "bcryptjs";
import { env } from "../config/env";

export function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}
export function verifyPassword(pw: string, hash: string): Promise<boolean> {
  return bcrypt.compare(pw, hash);
}
export function signJWT(payload: object): string {
  return jwt.sign(payload, env.jwtSecret, {
    expiresIn: "1h",
    issuer: "chat-server",
    audience: "chat-client"
  });
}
export function verifyJWT(token: string): jwt.JwtPayload | null {
  try {
    return jwt.verify(token, env.jwtSecret, {
      issuer: "chat-server",
      audience: "chat-client"
    });
  } catch {
    return null;
  }
}
```

#### WebSocket + Redis Pub/Sub (ws/wsServer.ts)
```typescript
import { WebSocketServer } from "bun";
import { verifyJWT } from "../services/auth";
import { Redis } from "ioredis";
const redisSubscriber = new Redis(env.redisUrl);
const redisPublisher = new Redis(env.redisUrl);

const wss = new WebSocketServer({ port: 8081 });
const clients = new Map<string, WebSocket>(); // userId -> ws

redisSubscriber.subscribe("chat-channel");
redisSubscriber.on("message", (channel, messageStr) => {
  if (channel === "chat-channel") {
    const message = JSON.parse(messageStr);
    for (const ws of clients.values()) {
      ws.send(JSON.stringify(message));
    }
  }
});

wss.on("connection", (ws, req) => {
  const token = req.headers["authorization"]?.replace("Bearer ", "");
  const payload = verifyJWT(token);
  if (!payload) { ws.close(); return; }
  const userId = payload.userId;
  clients.set(userId, ws);
  ws.on("message", async msg => {
    const parsed = JSON.parse(msg);
    // 메시지 DB 저장
    await messageService.save(parsed.content, userId);
    // Redis로 publish
    redisPublisher.publish("chat-channel", JSON.stringify({
      type: "message", content: parsed.content, sender: userId, timestamp: Date.now()
    }));
  });
  // ping/pong heartbeat, 탈락 자동 close
});
```

#### 메시지 저장 서비스 (services/messageService.ts)
```typescript
import { db } from "../db";
export async function save(content: string, userId: string) {
  await db.message.create({ data: { content, senderId: userId } });
}
export async function fetchRecent(n: number = 30) {
  return db.message.findMany({ orderBy: { timestamp: "desc" }, take: n });
}
```

#### 로그인 엔드포인트 (routes/login.ts)
```typescript
// POST /login
import { hashPassword, verifyPassword, signJWT } from "../services/auth";
import { db } from "../db";
export async function login(req) {
  const { username, password } = await req.json();
  const user = await db.user.findUnique({ where: { username } });
  if (!user || !(await verifyPassword(password, user.password))) {
    return new Response("Unauthorized", { status: 401 });
  }
  const jwt = signJWT({ userId: user.id });
  // refreshToken도 발급 (
  // Secure/HttpOnly Cookie로 전달)
  return new Response(null, {
    status: 200,
    headers: {
      "Set-Cookie": `token=${jwt}; HttpOnly; Secure` // Bun cookie set 예시
    }
  });
}
```

### 8. 운영/관찰성
- 헬스체크: `/health` 엔드포인트
- rate limiting: IP별/hour별 요청 카운트 utils/rateLimiter.ts
- 로깅: utils/logger.ts
- 테스트: Jest/Node.js로 로직 테스트, WebSocket load test 시나리오 작성
- 메트릭: 접속 사용자 수, 메시지 송수신량, latency 측정 가능하게 Prometheus 등 연동

---

### 결론
이 설계는:
- 분산 WebSocket 브로드캐스트와 메시지 영속화(확장/복구용),
- 현대적인 인증/보안 체계,
- 모듈화·운영성·테스트를 모두 고려하며,
- Bun에서 TypeScript로 프로덕션 요구사항을 충족하도록 구성
되어 있습니다.

현실적 확장성 확보가 가능하며, 실제 구현시 Bun의 cluster, Redis 설정, 로드밸런서(Proxy Protocol 지원) 등 실무 환경에 맞는 추가 구성이 선행되어야 합니다.
